/** Supported grant types */
type GrantType = 'authorization_code' | 'refresh_token';

/** A single client registration within a provider */
interface ClientRegistration {
  clientId: string;
  /** Key in Cloudflare env where this client's secret is stored */
  secretEnvKey: string;
}

/** Provider config — token URL and registered client IDs */
interface ProviderConfig {
  tokenUrl: string;
  clients: ClientRegistration[];
}

